package main

import "fmt"

func main() {
	var n int
	fmt.Scan(&n)
	v := make([]int, n)
	for i := range v {
		fmt.Scan(&v[i])
	}
	best, cur := v[0], v[0]
	for i := 1; i < n; i++ {
		cur = max(v[i], cur+v[i])
		best = max(best, cur)
	}
	fmt.Println(best)
}
